  const [loadingId, setLoadingId] = useState<string | null>(null);

  useEffect(() => {
    let cancelled = false;
    setError(null);
    catalogClient
      .listCatalogs()
      .then((list) => {
        if (!cancelled) setIndex(list);
      })
      .catch((err) => {
        if (!cancelled) setError(err instanceof Error ? err.message : String(err));
      });

